const BATCH = 10;
const MIN_AGE_HOURS = 24;
const BASE_URL = String($env.HOUSEX_PUBLIC_URL || 'https://timnhaxahoi.com').replace(/\/$/, '');

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

function parseDate(raw) {
  const t = Date.parse(String(raw || ''));
  return Number.isFinite(t) ? t : 0;
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  return [{ json: { empty: true, message: 'noxh_leads_ops trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const now = Date.now();
const minAgeMs = MIN_AGE_HOURS * 3600000;
const out = [];

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  const tier = String(row.tier || '').trim().toUpperCase();
  if (tier !== 'COLD' && tier !== 'OUT') continue;

  const email = String(row.contact_email || '').trim();
  if (!email || !email.includes('@')) continue;

  const meta = parseMeta(row.meta);
  if (meta.nurture_sent_at) continue;

  const createdAt = parseDate(row.created_at);
  if (createdAt && now - createdAt < minAgeMs) continue;

  const opsStatus = String(row.ops_status || '').trim().toLowerCase();
  if (opsStatus && !['nurture', 'new_cold', ''].includes(opsStatus)) continue;

  out.push({
    json: {
      ...row,
      tier,
      contact_email: email,
      contact_name: String(row.contact_name || 'Anh/Chị').trim(),
      reason_codes: String(row.reason_codes || ''),
      base_url: BASE_URL,
      meta_parsed: meta,
    },
  });

  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{
    json: {
      empty: true,
      message: 'Không có lead COLD/OUT chờ nurture (đã gửi hoặc chưa đủ tuổi)',
    },
  }];
}

return out;

const data = $getWorkflowStaticData('global');
data.nxn_stats = { sent: 0, failed: 0, skipped: 0 };
return $input.all();

const item = $input.first().json;
const name = item.contact_name || 'Anh/Chị';
const base = item.base_url || 'https://timnhaxahoi.com';
const tier = item.tier;
const reasons = String(item.reason_codes || '');

const links = {
  noxhArticle: `${base}/tin-tuc/dieu-kien-mua-nha-o-xa-hoi-2026-tom-tat`,
  loanCalc: `${base}/cong-cu/tinh-khoan-vay`,
  noxhProjects: `${base}/du-an?projectType=NHA_O_XA_HOI`,
  allProjects: `${base}/du-an`,
  contact: `${base}/lien-he`,
  noxhCheck: `${base}/cong-cu/dieu-kien-noxh`,
};

let subject;
let headline;
let bodyHtml;
let bodyText;

if (tier === 'OUT') {
  subject = 'HouseX — Gợi ý lộ trình mua nhà phù hợp với bạn';
  headline = 'Có thể bạn phù hợp nhà ở thương mại hơn NOXH';
  bodyHtml = `
<p>Xin chào ${name},</p>
<p>Cảm ơn bạn đã dùng công cụ kiểm tra điều kiện NOXH của HouseX. Theo thông tin bạn cung cấp, nhóm đối tượng hiện tại có thể chưa khớp chính sách nhà ở xã hội — nhưng vẫn có nhiều lựa chọn nhà ở thương mại và tư vấn tài chính phù hợp.</p>
<p><strong>Gợi ý bước tiếp theo:</strong></p>
<ul>
  <li><a href="${links.allProjects}">Xem dự án đang mở bán</a></li>
  <li><a href="${links.loanCalc}">Tính thử khoản vay mua nhà</a></li>
  <li><a href="${links.contact}">Đặt lịch tư vấn miễn phí với chuyên gia HouseX</a></li>
</ul>
<p>Chúng tôi sẵn sàng giải thích rõ hồ sơ và tìm giải pháp phù hợp — không áp lực mua bán.</p>
<p>Trân trọng,<br/>Đội ngũ HouseX</p>`;
  bodyText = `Xin chào ${name},\n\nCảm ơn bạn đã kiểm tra điều kiện NOXH. Nhóm đối tượng có thể chưa khớp NOXH — bạn có thể xem dự án: ${links.allProjects}\nTính vay: ${links.loanCalc}\nTư vấn: ${links.contact}\n\nTrân trọng, HouseX`;
} else {
  const incomeOver = reasons.includes('income_over_ceiling');
  const housingFail = reasons.includes('housing_fail');
  subject = incomeOver
    ? 'HouseX — Phương án nhà ở khi thu nhập vượt trần NOXH'
    : 'HouseX — Tài liệu & công cụ hữu ích cho hành trình mua nhà';
  headline = incomeOver
    ? 'Thu nhập trên ngưỡng NOXH — vẫn có lộ trình rõ ràng'
    : 'Chuẩn bị hồ sơ & công cụ cho quyết định mua nhà';

  const extra = incomeOver
    ? `<p>Thu nhập của bạn có thể vượt trần NOXH theo quy định hiện hành. HouseX gợi ý cân nhắc <a href="${links.allProjects}">nhà ở thương mại</a> hoặc liên hệ chuyên gia để rà soát lại hồ sơ (một số trường hợp vẫn có ngoại lệ cần xác minh).</p>`
    : housingFail
      ? `<p>Điều kiện nhà ở hiện tại có thể cần rà soát thêm. Chuyên gia HouseX có thể giúp bạn hiểu rõ quy định trước khi nộp hồ sơ chính thức.</p>`
      : `<p>Bạn có thể tiếp tục tìm hiểu điều kiện và chuẩn bị hồ sơ qua các tài liệu dưới đây.</p>`;

  bodyHtml = `
<p>Xin chào ${name},</p>
<p>Cảm ơn bạn đã sử dụng công cụ <a href="${links.noxhCheck}">Kiểm tra điều kiện NOXH</a> của HouseX.</p>
${extra}
<p><strong>Tài liệu & công cụ miễn phí:</strong></p>
<ul>
  <li><a href="${links.noxhArticle}">Tóm tắt điều kiện mua NOXH 2026</a></li>
  <li><a href="${links.loanCalc}">Tính khoản vay mua nhà</a></li>
  <li><a href="${links.noxhProjects}">Dự án NOXH đang mở bán</a></li>
  <li><a href="${links.contact}">Đặt lịch tư vấn với chuyên gia</a></li>
</ul>
<p>Khi bạn sẵn sàng, chúng tôi sẽ giải thích rõ tình trạng hồ sơ và tìm giải pháp phù hợp.</p>
<p>Trân trọng,<br/>Đội ngũ HouseX</p>`;
  bodyText = `Xin chào ${name},\n\nCảm ơn bạn đã dùng công cụ NOXH HouseX.\n\nBài viết: ${links.noxhArticle}\nTính vay: ${links.loanCalc}\nDự án NOXH: ${links.noxhProjects}\nTư vấn: ${links.contact}\n\nTrân trọng, HouseX`;
}

const html = `<!DOCTYPE html><html><body style="font-family:sans-serif;color:#333;line-height:1.6"><h2 style="color:#b81425">${headline}</h2>${bodyHtml}<p style="font-size:12px;color:#888">Bạn nhận email vì đã để lại thông tin trên HouseX. Nếu không muốn nhận thêm, trả lời email này.</p></body></html>`;

return [{
  json: {
    ...item,
    email_subject: subject,
    email_html: html,
    email_text: bodyText.slice(0, 8000),
  },
}];

const item = $input.first().json;
const enabled = String($env.NOXH_NURTURE_EMAIL_ENABLED || 'true').toLowerCase() === 'true';
const resendKey = $env.RESEND_API_KEY || '';
const from = $env.EMAIL_FROM || 'House X <noreply@timnhaxahoi.com>';

if (!enabled) {
  return [{
    json: {
      ...item,
      email_sent: false,
      email_skip: 'NOXH_NURTURE_EMAIL_ENABLED=false',
    },
  }];
}

if (!resendKey) {
  return [{
    json: {
      ...item,
      email_sent: false,
      email_skip: 'MISSING_RESEND_API_KEY',
    },
  }];
}

let res;
try {
  res = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.resend.com/emails',
    headers: {
      authorization: `Bearer ${resendKey}`,
      'content-type': 'application/json',
    },
    body: {
      from,
      to: [item.contact_email],
      subject: item.email_subject,
      html: item.email_html,
      text: item.email_text,
      tags: [{ name: 'noxh_nurture', value: item.tier }],
    },
    json: true,
    timeout: 20000,
  });
} catch (e) {
  return [{
    json: {
      ...item,
      email_sent: false,
      email_error: (e.message || String(e)).slice(0, 200),
    },
  }];
}

return [{
  json: {
    ...item,
    email_sent: !!res?.id,
    email_provider_id: res?.id || null,
  },
}];

const item = $input.first().json;
if (!item.email_sent || !item.sheet_row) {
  return [{ json: { ...item, sheet_updated: false } }];
}

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'noxh_leads_ops';
const row = item.sheet_row;
const col = 'O';

const meta = { ...(item.meta_parsed || {}), nurture_sent_at: new Date().toISOString(), nurture_tier: item.tier };
const metaStr = JSON.stringify(meta).slice(0, 45000);

return [{
  json: {
    ...item,
    meta_updated: metaStr,
    put_url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!${col}${row}`)}?valueInputOption=USER_ENTERED`,
    put_body: { values: [[metaStr]] },
  },
}];

const item = $input.first().json;
const sent = item.email_sent === true;
const data = $getWorkflowStaticData('global');
if (!data.nxn_stats) data.nxn_stats = { sent: 0, failed: 0, skipped: 0 };
if (sent) data.nxn_stats.sent += 1;
else if (item.email_skip) data.nxn_stats.skipped += 1;
else data.nxn_stats.failed += 1;

return [{
  json: {
    ...item,
    sheet_updated: sent && !!item.put_url,
  },
}];

const data = $getWorkflowStaticData('global');
const stats = data.nxn_stats || { sent: 0, failed: 0, skipped: 0 };
let hint = null;
if (stats.sent === 0 && stats.failed === 0) {
  hint = 'Không candidate — tier COLD/OUT, có email, chưa nurture_sent_at, đủ tuổi 24h';
} else if (stats.failed > 0) {
  hint = 'Một số email fail — kiểm tra RESEND_API_KEY và EMAIL_FROM';
}
return [{
  json: {
    ok: true,
    workflow: 'housex-noxh-nurture',
    stats,
    hint,
    finished_at: new Date().toISOString(),
  },
}];

const data = $getWorkflowStaticData('global');
if (!data.nxn_stats) data.nxn_stats = {};
return [{ json: { ok: true, empty: true, message: $input.first()?.json?.message || 'No nurture candidates', finished_at: new Date().toISOString() } }];
